<?php
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('invoices');
$pdo=getDB();
$id=(int)($_GET['id']??0);
$stmt=$pdo->prepare('SELECT * FROM ' . table('invoices') . ' WHERE id=? LIMIT 1');$stmt->execute([$id]);$invoice=$stmt->fetch();if(!$invoice){exit('Invoice not found.');}
$stmt=$pdo->prepare('SELECT ii.*,p.sku FROM ' . table('invoice_items') . ' ii LEFT JOIN ' . table('products') . ' p ON p.id=ii.product_id WHERE ii.invoice_id=? ORDER BY ii.id');$stmt->execute([$id]);$items=$stmt->fetchAll();
?>
<!doctype html><html><head><meta charset="utf-8"><title><?php echo esc($invoice['invoice_number']); ?></title><style>body{font-family:Arial,sans-serif;padding:40px;color:#111;background:#fff}.box{max-width:920px;margin:auto;border:1px solid #ddd;padding:32px}h1{margin:0 0 4px}.muted{color:#555}.grid{display:grid;grid-template-columns:1fr 1fr;gap:24px;margin:24px 0}table{width:100%;border-collapse:collapse;margin-top:20px}th,td{border-bottom:1px solid #ddd;padding:10px;text-align:left}th{text-transform:uppercase;font-size:12px}.totals{margin-left:auto;width:320px;margin-top:20px}.totals div{display:flex;justify-content:space-between;padding:5px 0}.grand{font-size:22px;font-weight:bold;border-top:2px solid #111;padding-top:12px!important}.print{margin-top:20px}@media print{.print{display:none}.box{border:0;padding:0}}</style></head><body><div class="box"><h1><?php echo esc(SHOP_NAME); ?></h1><div class="muted"><?php echo esc(SHOP_EMAIL); ?> · <?php echo esc(SHOP_PHONE); ?></div><hr><div class="grid"><div><h2>Invoice <?php echo esc($invoice['invoice_number']); ?></h2><div>Status: <strong><?php echo esc($invoice['status']); ?></strong></div><div>Due: <?php echo esc($invoice['due_date']); ?></div></div><div><h3>Bill To</h3><strong><?php echo esc($invoice['customer_name']); ?></strong><br><?php echo esc($invoice['customer_email']); ?><br><?php echo nl2br(esc($invoice['billing_address'])); ?></div></div><table><thead><tr><th>Description</th><th>SKU</th><th>Qty</th><th>Unit</th><th>Tax %</th><th>Line</th></tr></thead><tbody><?php foreach($items as $item): ?><tr><td><?php echo esc($item['description']); ?></td><td><?php echo esc($item['sku']); ?></td><td><?php echo esc($item['quantity']); ?></td><td><?php echo money($item['unit_price']); ?></td><td><?php echo esc($item['tax_rate']); ?></td><td><?php echo money($item['line_total']); ?></td></tr><?php endforeach; ?></tbody></table><div class="totals"><div><span>Subtotal</span><strong><?php echo money($invoice['subtotal']); ?></strong></div><div><span>Discount</span><strong><?php echo money($invoice['discount']); ?></strong></div><div><span>Tax</span><strong><?php echo money($invoice['tax']); ?></strong></div><div><span>Shipping</span><strong><?php echo money($invoice['shipping']); ?></strong></div><div class="grand"><span>Total</span><strong><?php echo money($invoice['total']); ?></strong></div><div><span>Paid</span><strong><?php echo money($invoice['amount_paid']); ?></strong></div><div><span>Balance</span><strong><?php echo money($invoice['balance_due']); ?></strong></div></div><button class="print" onclick="window.print()">Print Invoice</button></div></body></html>